from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a natural‑language description from a list of triples."""
    if not triples:
        return ""

    # helper to strip surrounding quotes
    def clean(val: str) -> str:
        return val.strip('\"')

    # group triples by subject to avoid repeating the subject many times
    grouped: dict[str, list[Triple]] = {}
    for t in triples:
        grouped.setdefault(t.subject, []).append(t)

    sentences: list[str] = []
    special_sentences: list[str] = []

    for subj, group in grouped.items():
        # collect clause fragments for this subject
        clauses: list[str] = []
        for t in group:
            p, o = t.predicate, clean(t.object)

            # Relations that read better as independent sentences
            if p == "musicFusionGenre":
                special_sentences.append(f"{o} is a musical fusion of {subj.lower()}.")
                continue
            if p == "musicSubgenre":
                special_sentences.append(f"{o} is a subgenre of {subj}.")
                continue
            if p == "derivative":
                special_sentences.append(f"{o} is a derivative of {subj}.")
                continue
            if p == "stylisticOrigin":
                special_sentences.append(f"{subj} originated from {o}.")
                continue

            if p == "birthDate":
                clauses.append(f"was born on {o}")
            elif p == "birthYear" or p == "birthPlace":
                clauses.append(f"was born in {o}")
            elif p == "deathDate":
                clauses.append(f"died on {o}")
            elif p == "deathPlace":
                clauses.append(f"died in {o}")
            elif p == "origin":
                clauses.append(f"originates from {o}")
            elif p == "genre":
                clauses.append(f"is a {o} musician")
            elif p == "instrument":
                clauses.append(f"plays {o}")
            elif p == "occupation":
                clauses.append(f"is a {o}")
            elif p == "background":
                # background often describes type of artist
                clauses.append(f"is a {o}")
            elif p == "associatedBand/associatedMusicalArtist":
                clauses.append(f"is associated with {o}")
            elif p == "recordLabel":
                clauses.append(f"is signed to {o}")
            elif p == "activeYearsStartYear":
                clauses.append(f"started their career in {o}")
            elif p == "activeYearsEndYear":
                clauses.append(f"ended their career in {o}")
            elif p == "nationality":
                clauses.append(f"is {o}")
            elif p == "capital":
                clauses.append(f"has capital {o}")
            elif p == "country":
                clauses.append(f"is in {o}")
            elif p == "isPartOf":
                clauses.append(f"is part of {o}")

